class Solution:
    def maximumSumOfHeights(self, maxHeights: List[int]) -> int:
        n = len(maxHeights)
        max_sum = 0

        for peak in range(n):
            # Build the mountain with peak at 'peak'
            heights = [0] * n
            # Non-decreasing up to peak
            heights[peak] = maxHeights[peak]
            for i in range(peak - 1, -1, -1):
                heights[i] = min(maxHeights[i], heights[i + 1])
            # Non-increasing after peak
            for i in range(peak + 1, n):
                heights[i] = min(maxHeights[i], heights[i - 1])
            # Check if it's a valid mountain
            valid = True
            for i in range(1, peak + 1):
                if heights[i - 1] > heights[i]:
                    valid = False
                    break
            for i in range(peak, n - 1):
                if heights[i] < heights[i + 1]:
                    valid = False
                    break
            if valid:
                max_sum = max(max_sum, sum(heights))

        return max_sum
